VOID SafeSyncRoutine(_In_ PDEVICE_OBJECT DeviceObject) {
    KIRQL oldIrql;
    UNREFERENCED_PARAMETER(DeviceObject);
    KeAcquireSpinLock(&g_SpinLock, &oldIrql);
    g_SharedCounter++;
    KeReleaseSpinLock(&g_SpinLock, oldIrql);
}

